@page "/apply/personal-info"
@rendermode InteractiveServer
@using sv_0af4ad347ecc46efa84e066ae2e51b02.Services
@inject WizardStateStore Store
@inject IHttpContextAccessor HttpContextAccessor
@inject PersistentComponentState PersistentState
@inject NavigationManager Navigation

<PageTitle>Personal Information – Apply</PageTitle>

<h3>Step 1: Personal Information</h3>

<div class="mb-3">
    <label class="form-label">Full Name</label>
    <input class="form-control" @bind="Data.FullName" @bind:event="oninput" />
</div>

<div class="mb-3">
    <label class="form-label">Email</label>
    <input type="email" class="form-control" @bind="Data.Email" @bind:event="oninput" />
</div>

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private string _sessionId = "";

    private ApplicationData Data { get; set; } = new();

    protected override void OnInitialized()
    {
        if (!PersistentState.TryTakeFromJson<string>("wizardSessionId", out var restored))
        {
            restored = HttpContextAccessor.HttpContext?.Session.Id;
        }
        _sessionId = restored ?? "";
        Data = Store.GetOrCreate(_sessionId);

        PersistentState.RegisterOnPersisting(() =>
        {
            PersistentState.PersistAsJson("wizardSessionId", _sessionId);
            return Task.CompletedTask;
        });
    }

    private void Next()
    {
        Data.CompletedSteps.Add(1);
        Navigation.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@using sv_0af4ad347ecc46efa84e066ae2e51b02.Services
@inject WizardStateStore Store
@inject IHttpContextAccessor HttpContextAccessor
@inject PersistentComponentState PersistentState
@inject NavigationManager Navigation

<PageTitle>Experience – Apply</PageTitle>

<h3>Step 2: Experience</h3>

@if (Data.JobHistory.Count > 0)
{
    <table class="table table-sm mb-3">
        <thead>
            <tr><th>Company</th><th>Title</th><th>Duration</th><th></th></tr>
        </thead>
        <tbody>
            @foreach (var job in Data.JobHistory)
            {
                <tr>
                    <td>@job.Company</td>
                    <td>@job.Title</td>
                    <td>@job.Duration</td>
                    <td><button class="btn btn-sm btn-outline-danger" @onclick="() => Data.JobHistory.Remove(job)">✕</button></td>
                </tr>
            }
        </tbody>
    </table>
}

<h5>Add Job</h5>
<div class="row g-2 mb-3">
    <div class="col-md-4">
        <input class="form-control" placeholder="Company" @bind="_newJob.Company" />
    </div>
    <div class="col-md-4">
        <input class="form-control" placeholder="Title" @bind="_newJob.Title" />
    </div>
    <div class="col-md-3">
        <input class="form-control" placeholder="Duration" @bind="_newJob.Duration" />
    </div>
    <div class="col-md-1">
        <button class="btn btn-success" @onclick="AddJob">+</button>
    </div>
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-outline-secondary" @onclick='() => Navigation.NavigateTo("/apply/personal-info")'>← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private string _sessionId = "";
    private JobEntry _newJob = new();

    private ApplicationData Data { get; set; } = new();

    protected override void OnInitialized()
    {
        if (!PersistentState.TryTakeFromJson<string>("wizardSessionId", out var restored))
        {
            restored = HttpContextAccessor.HttpContext?.Session.Id;
        }
        _sessionId = restored ?? "";
        Data = Store.GetOrCreate(_sessionId);

        PersistentState.RegisterOnPersisting(() =>
        {
            PersistentState.PersistAsJson("wizardSessionId", _sessionId);
            return Task.CompletedTask;
        });
    }

    private void AddJob()
    {
        if (!string.IsNullOrWhiteSpace(_newJob.Company))
        {
            Data.JobHistory.Add(_newJob);
            _newJob = new();
        }
    }

    private void Next()
    {
        Data.CompletedSteps.Add(2);
        Navigation.NavigateTo("/apply/references");
    }
}

@page "/apply/references"
