@using sv_0af4ad347ecc46efa84e066ae2e51b02.Services
@inject WizardStateStore Store
@inject IHttpContextAccessor HttpContextAccessor
@inject PersistentComponentState PersistentState
@inject NavigationManager Navigation

<PageTitle>References – Apply</PageTitle>

<h3>Step 3: References</h3>

@if (Data.References.Count > 0)
{
    <table class="table table-sm mb-3">
        <thead>
            <tr><th>Name</th><th>Email</th><th>Relationship</th><th></th></tr>
        </thead>
        <tbody>
            @foreach (var r in Data.References)
            {
                <tr>
                    <td>@r.Name</td>
                    <td>@r.Email</td>
                    <td>@r.Relationship</td>
                    <td><button class="btn btn-sm btn-outline-danger" @onclick="() => Data.References.Remove(r)">✕</button></td>
                </tr>
            }
        </tbody>
    </table>
}

<h5>Add Reference</h5>
<div class="row g-2 mb-3">
    <div class="col-md-4">
        <input class="form-control" placeholder="Name" @bind="_newRef.Name" />
    </div>
    <div class="col-md-4">
        <input class="form-control" placeholder="Email" @bind="_newRef.Email" />
    </div>
    <div class="col-md-3">
        <input class="form-control" placeholder="Relationship" @bind="_newRef.Relationship" />
    </div>
    <div class="col-md-1">
        <button class="btn btn-success" @onclick="AddReference">+</button>
    </div>
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-outline-secondary" @onclick='() => Navigation.NavigateTo("/apply/experience")'>← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private string _sessionId = "";
    private ReferenceContact _newRef = new();

    private ApplicationData Data { get; set; } = new();

    protected override void OnInitialized()
    {
        if (!PersistentState.TryTakeFromJson<string>("wizardSessionId", out var restored))
        {
            restored = HttpContextAccessor.HttpContext?.Session.Id;
        }
        _sessionId = restored ?? "";
        Data = Store.GetOrCreate(_sessionId);

        PersistentState.RegisterOnPersisting(() =>
        {
            PersistentState.PersistAsJson("wizardSessionId", _sessionId);
            return Task.CompletedTask;
        });
    }

    private void AddReference()
    {
        if (!string.IsNullOrWhiteSpace(_newRef.Name))
        {
            Data.References.Add(_newRef);
            _newRef = new();
        }
    }

    private void Next()
    {
        Data.CompletedSteps.Add(3);
        Navigation.NavigateTo("/apply/review");
    }
}

@page "/apply/review"
@rendermode InteractiveServer
@using sv_0af4ad347ecc46efa84e066ae2e51b02.Services
@inject WizardStateStore Store
@inject IHttpContextAccessor HttpContextAccessor
@inject PersistentComponentState PersistentState
@inject NavigationManager Navigation

<PageTitle>Review – Apply</PageTitle>

<h3>Step 4: Review Your Application</h3>

<div class="card mb-3">
    <div class="card-header"><strong>Personal Information</strong></div>
    <div class="card-body">
        <p><strong>Name:</strong> @Data.FullName</p>
        <p><strong>Email:</strong> @Data.Email</p>
    </div>
</div>

<div class="card mb-3">
    <div class="card-header"><strong>Experience</strong></div>
    <div class="card-body">
        @if (Data.JobHistory.Count == 0)
        {
            <p class="text-muted">No job history entered.</p>
        }
        else
        {
            <ul>
                @foreach (var job in Data.JobHistory)
                {
                    <li>@job.Title at @job.Company (@job.Duration)</li>
                }
            </ul>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header"><strong>References</strong></div>
    <div class="card-body">
        @if (Data.References.Count == 0)
        {
            <p class="text-muted">No references entered.</p>
        }
        else
        {
            <ul>
                @foreach (var r in Data.References)
                {
                    <li>@r.Name — @r.Email (@r.Relationship)</li>
                }
            </ul>
        }
    </div>
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-outline-secondary" @onclick='() => Navigation.NavigateTo("/apply/references")'>← Back</button>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@if (_submitted)
{
    <div class="alert alert-success mt-3">Your application has been submitted!</div>
}

@code {
    private string _sessionId = "";
    private bool _submitted;

    private ApplicationData Data { get; set; } = new();

    protected override void OnInitialized()
    {
        if (!PersistentState.TryTakeFromJson<string>("wizardSessionId", out var restored))
        {
            restored = HttpContextAccessor.HttpContext?.Session.Id;
        }
        _sessionId = restored ?? "";
        Data = Store.GetOrCreate(_sessionId);

        PersistentState.RegisterOnPersisting(() =>
        {
            PersistentState.PersistAsJson("wizardSessionId", _sessionId);
            return Task.CompletedTask;
        });
    }

    private void Submit()
    {
        Data.CompletedSteps.Add(4);
        _submitted = true;
        // In production: save to database, then Store.Remove(_sessionId)
    }
}

