    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 1.6rem;
    height: 1.6rem;
    border-radius: 50%;
    border: 2px solid #ccc;
    font-weight: 600;
    font-size: 0.8rem;
}

.wizard-step.active .step-number {
    border-color: #0d6efd;
    background: #0d6efd;
    color: #fff;
}

.wizard-step.active {
    color: #0d6efd;
    font-weight: 600;
}

.wizard-step.completed .step-number {
    border-color: #198754;
    background: #198754;
    color: #fff;
}

.wizard-step.completed {
    color: #198754;
}

.step-divider {
    color: #ccc;
    font-size: 1.1rem;
}

.step-label {
    white-space: nowrap;
}

